mapper.select:
SELECT COUNT(*) FROM TBL_JOB_APPLICATION A INNER JOIN TBL_JOB_POSTING J ON A.FK_JOB_ID = J.JOB_ID LEFT JOIN TBL_SUBMITTED_RESUME SR ON A.FK_SUBMITTED_RESUME_ID = SR.SUBMITTED_RESUME_ID WHERE J.FK_MEMBERID = #{memberId} AND A.APPLICATION_STATUS = 0
AND ( A.NAME LIKE '%' || #{keyword} || '%' OR A.EMAIL LIKE '%' || #{keyword} || '%' )
AND A.PROCESS_STATUS = #{processStatus}
AND A.FK_JOB_ID = #{jobId}

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A.APPLIED_AT DESC, A.APPLICATION_ID DESC) AS RNO, A.APPLICATION_ID, A.FK_JOB_ID, A.FK_MEMBERID, A.FK_SUBMITTED_RESUME_ID, A.NAME, A.BIRTH_DATE, A.GENDER, A.PHONE, A.EMAIL, A.APPLICATION_ROUND, A.APPLICATION_STATUS, A.PROCESS_STATUS, A.APPLIED_AT, A.CANCELLED_AT, A.VIEWED_AT, J.TITLE AS JOB_TITLE, SR.TITLE AS RESUME_TITLE, SR.DESIRED_SALARY AS DESIRED_SALARY FROM TBL_JOB_APPLICATION A INNER JOIN TBL_JOB_POSTING J ON A.FK_JOB_ID = J.JOB_ID LEFT JOIN TBL_SUBMITTED_RESUME SR ON A.FK_SUBMITTED_RESUME_ID = SR.SUBMITTED_RESUME_ID WHERE J.FK_MEMBERID = #{memberId} AND A.APPLICATION_STATUS = 0
AND ( A.NAME LIKE '%' || #{keyword} || '%' OR A.EMAIL LIKE '%' || #{keyword} || '%' )
AND A.PROCESS_STATUS = #{processStatus}
AND A.FK_JOB_ID = #{jobId}
) WHERE RNO BETWEEN #{startRow} AND #{endRow}

SELECT A.PROCESS_STATUS
FROM TBL_JOB_APPLICATION A
INNER JOIN TBL_JOB_POSTING J
    ON A.FK_JOB_ID = J.JOB_ID
WHERE A.APPLICATION_ID = #{applicationId}
  AND J.FK_MEMBERID = #{memberId}

mapper.update:
UPDATE TBL_JOB_APPLICATION
   SET PROCESS_STATUS = 1,
       VIEWED_AT = SYSDATE
 WHERE APPLICATION_ID = #{applicationId}
   AND PROCESS_STATUS = 0
   AND FK_JOB_ID IN (
        SELECT JOB_ID
          FROM TBL_JOB_POSTING
         WHERE FK_MEMBERID = #{memberId}
   )

UPDATE TBL_JOB_APPLICATION
   SET PROCESS_STATUS = #{newStatus}
 WHERE APPLICATION_ID = #{applicationId}
   AND PROCESS_STATUS != 0
   AND FK_JOB_ID IN (
        SELECT JOB_ID
          FROM TBL_JOB_POSTING
         WHERE FK_MEMBERID = #{memberId}
   )
